#!/usr/bin/env python3

# FizzBuzz implementation
# Prints numbers 1 to 100
# - "Fizz" for multiples of 3
# - "Buzz" for multiples of 5
# - "FizzBuzz" for multiples of both 3 and 5
# One value per line

def fizzbuzz():
    for i in range(1, 101):
        if i % 15 == 0:  # Check for multiples of both 3 and 5 first
            print("FizzBuzz")
        elif i % 3 == 0:
            print("Fizz")
        elif i % 5 == 0:
            print("Buzz")
        else:
            print(i)

if __name__ == "__main__":
    fizzbuzz()
